import type { CareerQuestion } from "./rrt-questions";

export const psychotherapistQuestionsBatch6: CareerQuestion[] = [
  { id: "rp-851", stem: "In Bowen's family systems theory, 'differentiation of self' refers to:", options: ["The ability to maintain one's sense of self while remaining emotionally connected to the family","Complete emotional separation from the family of origin","The therapist's personal maturity level","A child's cognitive developmental stage"], correctIndex: 0, rationale: "Differentiation of self is Bowen's core concept describing the capacity to think independently while staying emotionally connected to important others. Low differentiation leads to emotional fusion or reactive cutoff.", difficulty: 2, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-852", stem: "In structural family therapy, Salvador Minuchin uses 'enactment' to:", options: ["Have family members interact with each other in session to observe and modify their transactional patterns directly","Ask family members to write letters to each other","Have each family member describe the family from their perspective","Assign behavioral homework for the week"], correctIndex: 0, rationale: "Enactment in structural family therapy involves directing family members to interact around a problem in session. This allows the therapist to observe patterns in real-time and intervene to restructure dysfunctional transactions.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-853", stem: "The Milan systemic model is distinguished by its use of:", options: ["Circular questioning, hypothesizing, and neutrality","Paradoxical interventions exclusively","Behavioral reinforcement schedules","Individual psychodynamic interpretation within the family context"], correctIndex: 0, rationale: "The Milan systemic approach (Selvini Palazzoli) introduced circular questioning (exploring differences in perception and relationship patterns), hypothesizing (forming systemic hypotheses before sessions), and neutrality (avoiding alliances).", difficulty: 3, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-854", stem: "A genogram is a clinical tool used in family therapy to:", options: ["Map multigenerational family structure, relationships, and patterns across at least three generations","Measure individual personality traits","Assess cognitive functioning","Record session-by-session progress notes"], correctIndex: 0, rationale: "A genogram is a graphic representation of a family's multigenerational structure using standardized symbols. It identifies patterns of illness, relationship dynamics, emotional cutoffs, and intergenerational transmission of behaviors.", difficulty: 1, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-855", stem: "In Bowen's theory, 'triangulation' serves the function of:", options: ["Stabilizing a two-person relationship by involving a third person to manage anxiety","Creating alliances to exclude family members permanently","Improving communication between all three members equally","Resolving conflict through majority voting"], correctIndex: 0, rationale: "Bowen described triangulation as the basic building block of emotional systems. When anxiety in a dyad exceeds their tolerance, they recruit a third person to stabilize the system, though this prevents direct resolution of the original tension.", difficulty: 2, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-856", stem: "Strategic family therapy, associated with Jay Haley, is characterized by:", options: ["The therapist designing specific interventions to alter dysfunctional interactional sequences","A non-directive, reflective therapeutic stance","Exclusive focus on individual intrapsychic conflict","Long-term exploration of unconscious family dynamics"], correctIndex: 0, rationale: "Strategic family therapy is directive and problem-focused. The therapist takes responsibility for planning interventions that target specific behavioral sequences maintaining the problem, often using directives and homework assignments.", difficulty: 2, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-857", stem: "Bowen's concept of 'emotional cutoff' describes:", options: ["A person's attempt to manage unresolved emotional issues with family by reducing or severing contact","A therapeutic technique for ending sessions","The healthy establishment of boundaries between generations","The natural conclusion of grief after a family death"], correctIndex: 0, rationale: "Emotional cutoff is an extreme form of managing fusion with the family of origin by physically or emotionally distancing. While it may reduce overt anxiety, it leaves the underlying attachment issues unresolved and often leads to their repetition in new relationships.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-858", stem: "In structural family therapy, 'enmeshment' refers to:", options: ["Diffuse boundaries between family members resulting in over-involvement and loss of individual autonomy","Clear and healthy boundaries","Emotional distance between family members","A hierarchical power structure"], correctIndex: 0, rationale: "Enmeshment (Minuchin) describes family subsystems with diffuse boundaries where members are excessively involved in each other's lives, sacrificing individual autonomy. Changes in one member immediately resonate throughout the enmeshed system.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-859", stem: "A family therapist notices that whenever the parents begin to argue, their 12-year-old develops a stomachache, redirecting attention. This pattern is best understood as:", options: ["The child functioning as a 'symptom bearer' or 'identified patient' to maintain family homeostasis","A coincidental medical condition","The child's manipulative behavior requiring discipline","Evidence of a genuine gastrointestinal disorder"], correctIndex: 0, rationale: "The identified patient concept in family systems theory suggests that one family member's symptoms serve a homeostatic function - stabilizing the family system by diverting attention from the real issue (marital conflict) to the child's symptoms.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-860", stem: "Narrative family therapy, developed by White and Epston, uses 'externalizing conversations' to:", options: ["Separate the problem from the person's identity, allowing the family to unite against the problem","Avoid discussing problems within the family","Project blame onto external circumstances","Encourage family members to express anger outwardly"], correctIndex: 0, rationale: "Externalizing conversations linguistically separate the problem from the family/person ('the anxiety' rather than 'your anxiety problem'). This reduces blame, decreases defensiveness, and enables the family to collaborate against the externalized problem.", difficulty: 2, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-861", stem: "The concept of 'family life cycle' (Carter and McGoldrick) identifies that families experience predictable stress during:", options: ["Major transitions such as marriage, birth of children, children leaving home, and retirement","Only unexpected crises like death or illness","The first year of marriage exclusively","Childhood developmental milestones only"], correctIndex: 0, rationale: "Carter and McGoldrick identified normative family life cycle stages (coupling, families with young children, adolescents, launching, later life). Transitions between stages create predictable stress requiring adaptation and renegotiation of family roles.", difficulty: 1, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-862", stem: "In circular questioning (Milan model), the therapist asks one family member to comment on the relationship between two other family members. This technique is used to:", options: ["Reveal differences in perception and elicit information about relational patterns","Test family members' observation skills","Create conflict for therapeutic purposes","Identify the most insightful family member"], correctIndex: 0, rationale: "Circular questions explore relational patterns by asking third parties to comment on dyadic interactions. This reveals differences in perception, introduces new information into the system, and highlights recursive interactional patterns.", difficulty: 3, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-863", stem: "Bowen's concept of the 'nuclear family emotional system' describes:", options: ["Four patterns of managing anxiety in the nuclear family: marital conflict, dysfunction in a spouse, impairment of one or more children, and emotional distance","Only the mother-child relationship pattern","Financial management within the family","The family's genetic inheritance patterns"], correctIndex: 0, rationale: "Bowen identified four patterns through which undifferentiation and anxiety are managed in the nuclear family: marital conflict, dysfunction in one spouse, projection to a child, and emotional distance. These patterns often operate simultaneously.", difficulty: 4, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-864", stem: "In structural family therapy, the concept of 'hierarchy' refers to:", options: ["The distribution of power and authority within the family, with parents ideally holding executive authority over children","Every family member having equal decision-making power","The oldest family member always being in charge","A rigid patriarchal structure"], correctIndex: 0, rationale: "Minuchin emphasized clear hierarchical organization with parents forming an executive subsystem. Dysfunctional hierarchies include parentified children, cross-generational coalitions, or parents who abdicate authority.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-865", stem: "A therapist using strategic family therapy assigns the family a 'paradoxical directive' to:", options: ["Prescribe the symptomatic behavior to disrupt the family's homeostatic pattern","Encourage the family to continue healthy behaviors","Test whether the family will comply with straightforward instructions","Provoke anger to facilitate emotional expression"], correctIndex: 0, rationale: "Paradoxical directives (prescribing the symptom) create a therapeutic double bind. If the family follows the directive, the symptom becomes voluntary and loses its function. If they resist, they change the problematic pattern.", difficulty: 3, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-866", stem: "In narrative family therapy, 'unique outcomes' or 'sparkling moments' refer to:", options: ["Times when the problem did not dominate or the family responded differently than the problem-saturated story suggests","Unusual family crisis events","The therapist's unique interventions","Exceptional therapeutic breakthroughs only"], correctIndex: 0, rationale: "Unique outcomes are exceptions to the dominant problem-saturated narrative. The therapist helps the family identify times when they acted against the problem, using these as entry points for constructing a preferred alternative story.", difficulty: 3, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-867", stem: "Bowen's 'family projection process' describes how:", options: ["Parents transmit their emotional problems to a child through projection of anxiety and undifferentiation","Children project their school problems onto parents","The therapist projects interpretations onto the family","Extended family members influence the nuclear family"], correctIndex: 0, rationale: "The family projection process describes how parents transmit their level of differentiation and anxiety to one or more children. The child most involved in the process develops lower differentiation and is more vulnerable to symptoms.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-868", stem: "A structural family therapist uses 'joining' at the beginning of therapy to:", options: ["Accommodate to the family's style and establish a therapeutic alliance with the family system","Force the family to accept the therapist's authority","Immediately challenge the family's dysfunctional patterns","Identify the most disturbed family member"], correctIndex: 0, rationale: "Joining (Minuchin) involves the therapist accommodating to the family's communication style, respecting hierarchy, and building rapport with all members. Without adequate joining, restructuring interventions are likely to be rejected.", difficulty: 1, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-869", stem: "In the family life cycle framework, the 'launching' stage is characterized by:", options: ["Young adult children leaving home and parents renegotiating the marital dyad","The birth of the first child","The wedding of the couple","The death of a grandparent"], correctIndex: 0, rationale: "The launching stage involves young adults separating from the family of origin while maintaining connection. Parents must renegotiate their relationship as a dyad, develop adult-to-adult relationships with children, and adjust to empty nest transitions.", difficulty: 2, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-870", stem: "The Milan systemic team originally used a 'therapeutic team' format involving:", options: ["A team behind a one-way mirror who observed the session and consulted with the therapist during an intersession break","Multiple therapists simultaneously treating the family","Family members observing themselves on video replay","Individual sessions with each family member by different therapists"], correctIndex: 0, rationale: "The Milan team used a reflecting team behind a one-way mirror. The session included a pre-session hypothesis, the interview, an intersession discussion (therapists conferred with the team), and delivery of the end-of-session intervention.", difficulty: 3, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-871", stem: "In a genogram, a square symbol represents:", options: ["A male family member","A female family member","A deceased family member","A conflictual relationship"], correctIndex: 0, rationale: "Standard genogram notation uses squares for males, circles for females. Additional symbols indicate marriages, divorces, pregnancies, deaths (X through the shape), and various relationship qualities (close, conflictual, distant, cutoff).", difficulty: 1, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-872", stem: "A couple presents with a pattern where one partner pursues emotional closeness and the other withdraws. This 'pursuer-distancer' dynamic is best understood through:", options: ["Systemic/circular causality where each partner's behavior reinforces the other's pattern","Linear causality blaming one partner for the problem","Individual psychopathology in the pursuing partner","Cultural differences in emotional expression only"], correctIndex: 0, rationale: "The pursuer-distancer pattern is a classic circular interactional sequence. The pursuer's seeking drives the distancer away, and the distancer's withdrawal intensifies the pursuer's pursuit. Treatment targets the recursive loop, not individual blame.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-873", stem: "Bowen's concept of 'multigenerational transmission process' suggests that:", options: ["Patterns of differentiation are passed down through multiple generations, with some family lines becoming progressively less differentiated","Each generation starts fresh with no influence from previous generations","Only genetic traits are transmitted across generations","Cultural values are the only multigenerational influence"], correctIndex: 0, rationale: "The multigenerational transmission process describes how small differences in differentiation levels accumulate over generations through the family projection process. Some family lines achieve progressively higher differentiation while others decline.", difficulty: 4, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-874", stem: "In structural family therapy, 'boundary making' involves the therapist:", options: ["Intervening to create clearer boundaries between enmeshed subsystems or soften rigid ones","Setting rules about session attendance","Establishing the physical seating arrangement only","Determining who speaks first in each session"], correctIndex: 0, rationale: "Boundary making is a restructuring technique where the therapist actively intervenes to establish clearer subsystem boundaries (e.g., blocking intrusion between parent and child subsystems or increasing permeability of rigid boundaries).", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-875", stem: "In narrative family therapy, 're-authoring' or 're-storying' involves:", options: ["Helping the family construct an alternative, preferred narrative that incorporates unique outcomes and new meaning","The therapist writing a new story for the family to follow","Editing family photographs to reframe memories","Literally rewriting family history documents"], correctIndex: 0, rationale: "Re-authoring (White) involves thickening the alternative story by linking unique outcomes across time, exploring what these say about the family's values and intentions, and developing a richer, preferred account of family identity and relationships.", difficulty: 3, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-876", stem: "The concept of 'homeostasis' in family systems theory describes:", options: ["The family system's tendency to maintain its current equilibrium and resist change","The ideal state of family functioning","A therapeutic goal of achieving perfect balance","The physiological regulation of family members' health"], correctIndex: 0, rationale: "Family homeostasis refers to the self-regulating tendency of family systems to maintain familiar patterns, even dysfunctional ones. This resistance to change is a fundamental systemic concept explaining why symptoms persist and change is difficult.", difficulty: 1, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-877", stem: "A strategic family therapist focuses on the 'presenting problem' because:", options: ["The symptom is understood as embedded in the family's interactional sequences, and changing those sequences resolves the problem","Individual pathology is the primary concern","The family's history is more important than current functioning","Systemic patterns are considered irrelevant"], correctIndex: 0, rationale: "Strategic therapy (Haley, Madanes) views symptoms as maintained by recursive interactional sequences. The therapist designs specific interventions to interrupt these sequences, making the symptom no longer necessary for the system.", difficulty: 2, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-878", stem: "In a genogram, a zigzag line between two family members typically represents:", options: ["A conflictual or hostile relationship","An emotionally close relationship","A distant relationship","An enmeshed relationship"], correctIndex: 0, rationale: "Standard genogram symbols include zigzag or sawtooth lines for conflictual relationships, double lines for close/intimate relationships, dotted lines for distant relationships, and a combination for close-conflictual (fused) relationships.", difficulty: 1, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-879", stem: "Carter and McGoldrick identified that immigrant families face additional stress related to:", options: ["Navigating normative family life cycle transitions while simultaneously adjusting to a new cultural context","Only language barriers","Exclusively financial difficulties","The children's school performance alone"], correctIndex: 0, rationale: "Immigrant families face the intersection of normative family life cycle tasks with acculturative stress, including language barriers, cultural value conflicts, shifts in gender roles, intergenerational acculturation gaps, and loss of extended family support.", difficulty: 2, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-880", stem: "In structural family therapy, a 'cross-generational coalition' is considered dysfunctional because:", options: ["It involves a parent and child aligning against the other parent, undermining the parental hierarchy","All family alliances are inherently pathological","Children should never have close relationships with parents","It prevents siblings from forming bonds"], correctIndex: 0, rationale: "Cross-generational coalitions (e.g., mother-child against father) violate the hierarchical structure by placing a child in the parental subsystem. This undermines parental authority, triangulates the child, and maintains marital conflict indirectly.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-881", stem: "The Milan systemic concept of 'positive connotation' involves:", options: ["Reframing the symptomatic behavior as serving a positive function for the family system","Praising the family member with the most positive behavior","Ignoring negative behaviors and reinforcing positive ones","The therapist maintaining a cheerful disposition"], correctIndex: 0, rationale: "Positive connotation ascribes positive motives to symptomatic behavior (e.g., 'Your depression is protecting the family from dealing with the parents' marital issue'). This systemic reframe challenges the identified patient concept and engages the whole system.", difficulty: 4, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-882", stem: "Bowen's 'societal regression' concept extends his theory by suggesting that:", options: ["Society as a whole can demonstrate decreased differentiation during periods of chronic anxiety, similar to family systems","Societal change has no impact on family functioning","Only individual families experience regression","Political systems are immune to emotional process"], correctIndex: 0, rationale: "Bowen extended his theory to societal level, proposing that chronic societal anxiety leads to emotional regression where society functions at lower levels of differentiation - making decisions based on feeling rather than thinking, similar to poorly differentiated families.", difficulty: 4, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-883", stem: "A family therapist observes that an adolescent's eating disorder worsens whenever the parents discuss separation. The therapist hypothesizes that:", options: ["The eating disorder serves a homeostatic function by diverting parental attention from their marital crisis","The eating disorder is purely biological","The adolescent is being deliberately manipulative","The parents' discussion is coincidental to symptom fluctuation"], correctIndex: 0, rationale: "From a systemic perspective, the symptom's correlation with parental conflict suggests it serves a protective function - keeping the parents focused on the child and postponing their separation. Treatment should address both the symptom and the systemic function.", difficulty: 3, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-884", stem: "In narrative family therapy, 'definitional ceremonies' involve:", options: ["Inviting an audience of significant others to witness and acknowledge the client's preferred story and identity","Formal diagnostic assessment rituals","Graduation ceremonies marking the end of therapy","Religious ceremonies incorporated into treatment"], correctIndex: 0, rationale: "White adapted Barbara Myerhoff's concept of definitional ceremonies as therapeutic events where outsider witnesses reflect on and authenticate the client's preferred story, contributing to the thickening and social validation of the alternative narrative.", difficulty: 4, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-885", stem: "In Bowen theory, the 'sibling position' concept draws on Toman's work and suggests that:", options: ["Birth order characteristics influence personality development and marital compatibility based on complementary sibling roles","All siblings develop identical personality traits","Birth order has no clinical relevance","Only the eldest child is affected by family dynamics"], correctIndex: 0, rationale: "Bowen incorporated Toman's sibling position profiles, noting that functional birth order (which may differ from actual) influences personality and that couples with complementary sibling positions (e.g., oldest-youngest) tend to have fewer adjustment issues.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-886", stem: "Structural family therapy identifies three types of boundaries:", options: ["Clear, rigid, and diffuse","Good, bad, and neutral","Internal, external, and permeable","Spoken, unspoken, and negotiated"], correctIndex: 0, rationale: "Minuchin described boundaries on a continuum: clear boundaries allow appropriate exchange while maintaining differentiation (healthy), rigid boundaries result in disengagement (too little exchange), and diffuse boundaries lead to enmeshment (excessive exchange).", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-887", stem: "A family therapist conducting a genogram discovers a pattern of alcoholism appearing in every generation. This illustrates:", options: ["Multigenerational transmission of patterns","A coincidental finding","A purely genetic phenomenon","The result of cultural norms alone"], correctIndex: 0, rationale: "While genetics play a role in alcoholism, the multigenerational pattern on the genogram also reflects the transmission of coping strategies, relationship patterns, emotional processes, and family culture that maintain substance use across generations.", difficulty: 2, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-888", stem: "The concept of 'circular causality' in family systems theory differs from 'linear causality' in that:", options: ["Events are understood as part of reciprocal, recursive feedback loops rather than simple cause-and-effect chains","It focuses on one person causing the family's problems","It assigns blame to the earliest event in the family's history","It eliminates the concept of causation entirely"], correctIndex: 0, rationale: "Circular causality is a foundational systemic concept. Rather than A causing B (linear), family patterns are understood as recursive loops where A influences B, which in turn influences A, creating self-reinforcing interactional patterns.", difficulty: 2, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-889", stem: "Strategic family therapist Cloe Madanes developed which approach to addressing family power dynamics?", options: ["Pretend techniques where family members act 'as if' to shift power imbalances","Psychoeducational lectures on power","Medication management for the most powerful family member","Removal of the most dominant family member from treatment"], correctIndex: 0, rationale: "Madanes developed pretend techniques (e.g., asking a child to pretend to have the symptom) to expose and shift the incongruent hierarchy in the family. These playful directives revealed the function of symptoms in maintaining power arrangements.", difficulty: 4, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-890", stem: "In the family life cycle, the transition to parenthood is considered particularly stressful because it requires:", options: ["Reorganizing the marital dyad to include a third member, shifting from a two-person to a three-person system","Simply adding a new family member without systemic change","Only financial adjustment","Returning to the parents' own childhood patterns"], correctIndex: 0, rationale: "The transition to parenthood requires fundamental systemic reorganization: creating a parental subsystem, renegotiating the marital relationship, adjusting extended family relationships, and managing the tension between autonomy and responsibility.", difficulty: 2, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-891", stem: "Tom Andersen's 'reflecting team' approach involves:", options: ["The observing team openly sharing their reflections with the family, who then discusses the team's observations","The team providing a definitive diagnosis to the family","The team secretly rating the family's interactions","The team directing the therapist's interventions from behind the mirror"], correctIndex: 0, rationale: "Andersen's reflecting team approach reversed the traditional hidden team format. The team openly shares tentative observations and ideas with the family, who then discusses which reflections resonated. This democratic process respects the family's agency.", difficulty: 3, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-892", stem: "Bowen defined 'fusion' as:", options: ["Emotional merging where individuals lose their sense of self and become reactive to the emotional state of others","A positive therapeutic outcome","Physical closeness between family members","A technique for joining with the family"], correctIndex: 0, rationale: "Fusion represents the opposite pole from differentiation. Fused individuals have poorly defined ego boundaries, are highly reactive to others' emotions, and make decisions based on feeling pressures from the relationship system rather than thoughtful self-direction.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-893", stem: "In structural family therapy, 'unbalancing' involves:", options: ["The therapist deliberately siding with one family member to challenge the existing power structure","Maintaining strict therapeutic neutrality at all times","Equally validating all family members' perspectives","Avoiding any alliance with family subsystems"], correctIndex: 0, rationale: "Unbalancing is a restructuring technique where the therapist affiliates with one family member or subsystem to challenge existing power dynamics. By aligning with a disempowered member, the therapist disrupts the dysfunctional equilibrium.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-894", stem: "In narrative family therapy, 'thickening the alternative story' involves:", options: ["Elaborating the preferred narrative by exploring its history, meaning, and implications for the future","Making the therapy sessions longer","Adding more details to the problem story","Including more family members in sessions"], correctIndex: 0, rationale: "Thickening the alternative story involves linking unique outcomes across time, inviting reflection on what they mean about the person's values and identity, recruiting witnesses, and extending the story into an anticipated future.", difficulty: 3, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-895", stem: "A genogram revealing that three consecutive generations of women married alcoholic men suggests:", options: ["An intergenerational relational pattern that may involve repetitive choice of partners based on internalized family templates","Random coincidence","Genetic predisposition in the women","Cultural mandate for such marriages"], correctIndex: 0, rationale: "The genogram reveals a multigenerational pattern of partner selection. From a systemic perspective, each generation's relational templates, attachment patterns, and familiarity with alcoholic family dynamics influence unconscious partner choice.", difficulty: 3, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-896", stem: "In Bowen theory, 'emotional process in society' suggests that the therapist should:", options: ["Be aware of how broader societal emotional processes affect families and individual functioning","Focus exclusively on the nuclear family","Ignore social context in treatment planning","Only treat families from similar social backgrounds"], correctIndex: 0, rationale: "Bowen extended his theory to societal level, recognizing that chronic societal anxiety, cultural forces, and institutional emotional processes influence family functioning. Therapists must consider these broader systemic contexts in treatment.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-897", stem: "A structural family therapist asks a disengaged father to sit next to his daughter during a session and talk to her about her school day. This intervention is called:", options: ["Restructuring through proximity and enactment","Paradoxical intervention","Circular questioning","Positive connotation"], correctIndex: 0, rationale: "The therapist uses spatial proximity (changing seating) and enactment (directing interaction) to restructure the disengaged father-daughter subsystem. This in-session experience creates new transactional patterns that can generalize outside therapy.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-898", stem: "The Milan systemic concept of 'hypothesizing' involves:", options: ["The team formulating a systemic hypothesis about the family's relational pattern before the session to guide circular questioning","Guessing the family's diagnosis","The family making hypotheses about the therapist","A research methodology used in outcome studies"], correctIndex: 0, rationale: "Pre-session hypothesizing in the Milan model involves the team generating a systemic hypothesis about the family's relational pattern and the function of the symptom. This guides the circular questioning but remains open to revision based on new information.", difficulty: 3, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-899", stem: "In the family life cycle, the 'family with adolescents' stage requires parents to:", options: ["Increase flexibility of family boundaries to allow adolescent independence while maintaining appropriate limits","Maintain the same level of control as during early childhood","Disengage completely from the adolescent's life","Focus exclusively on academic achievement"], correctIndex: 0, rationale: "Families with adolescents must shift from the hierarchical, protective structure of earlier stages to increased permeability of boundaries that allows age-appropriate autonomy while maintaining parental guidance and safety.", difficulty: 2, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-900", stem: "In strategic family therapy, Haley's concept of 'incongruent hierarchy' describes:", options: ["A dysfunctional family structure where a child holds more power than the parents, often through symptomatic behavior","The therapist's hierarchical relationship with the family","The order in which family members speak in session","An organizational chart for the treatment team"], correctIndex: 0, rationale: "Haley described how symptoms in children often reflect an incongruent hierarchy where the child's symptoms place them in a one-up position relative to the parents, inverting the appropriate generational power structure.", difficulty: 3, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-901", stem: "A family therapist using narrative techniques asks: 'How has anxiety been affecting your family's life?' rather than 'Why is your family so anxious?' This shift in language demonstrates:", options: ["Externalization - positioning the problem as separate from the family's identity","Minimization of the family's distress","Denial of the problem's severity","Intellectual distancing from emotional content"], correctIndex: 0, rationale: "Externalizing language positions 'anxiety' as an external entity affecting the family rather than an inherent quality of the family. This reduces blame, opens space for agency, and enables the family to take a stance against the problem.", difficulty: 2, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-902", stem: "Bowen's 'coach' role in therapy involves:", options: ["Working primarily with the most motivated family member to increase their differentiation, which will influence the system","Directing all family members' behavior in session","Providing psychoeducation through lectures","Acting as a surrogate family member"], correctIndex: 0, rationale: "Bowen therapists often work with one motivated individual rather than the whole family, coaching them to increase differentiation within their family system. As one member changes, the system responds and shifts, demonstrating systemic influence.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-903", stem: "In structural family therapy, 'mapping' the family involves:", options: ["Creating a visual diagram of the family's structure including subsystems, boundaries, and power dynamics","Drawing a floor plan of the family's home","Recording family members' movements during the session","Creating a geographic map of where family members live"], correctIndex: 0, rationale: "Structural mapping uses specific notation to diagram family subsystems, boundary types (clear, diffuse, rigid), coalitions, conflicts, and power dynamics. This visual tool guides the therapist's assessment and intervention planning.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-904", stem: "The concept of 'first-order change' versus 'second-order change' in family systems distinguishes between:", options: ["Superficial changes within the existing system structure versus fundamental changes that transform the system's rules","The first and second family therapy sessions","Changes made by the first-born versus second-born child","Sequential steps in a treatment plan"], correctIndex: 0, rationale: "First-order change involves modifications within the existing system rules (doing more or less of the same). Second-order change transforms the rules themselves, producing a qualitatively different pattern of interaction.", difficulty: 4, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-905", stem: "In the genogram, a horizontal line connecting two symbols with a single slash through it indicates:", options: ["A separated couple","A divorced couple","A married couple","A cohabiting couple"], correctIndex: 0, rationale: "In standard genogram notation, a single slash through the horizontal marriage line indicates separation. A double slash indicates divorce. An uninterrupted line indicates an intact marriage or partnership.", difficulty: 1, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-906", stem: "A family in which the grandmother acts as the primary disciplinarian while the mother defers to her own mother demonstrates:", options: ["A cross-generational coalition between grandmother and children that undermines the parental subsystem","A healthy extended family arrangement","Normal cultural variation requiring no clinical attention","The grandmother's appropriate authority"], correctIndex: 0, rationale: "When the grandmother usurps the parental executive function, it creates a cross-generational coalition that undermines the mother's authority and blurs generational boundaries. Structural therapy would work to restore the mother's position in the hierarchy.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-907", stem: "Milan systemic therapy distinguishes between 'neutrality' and 'curiosity.' Cecchin reformulated neutrality as:", options: ["Curiosity - a genuinely interested, non-judgmental stance that views all behaviors as making sense within their context","Complete indifference to the family's problems","Agreement with every family member's perspective","The therapist's emotional detachment"], correctIndex: 0, rationale: "Cecchin reconceptualized therapeutic neutrality as curiosity - a stance of genuine interest in understanding how each family member's behavior makes sense within the relational context. This replaced the sometimes-criticized concept of neutrality as coldness.", difficulty: 4, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-908", stem: "The family life cycle stage of 'coupling' involves two key tasks:", options: ["Commitment to a new system and realignment of relationships with families of origin and peers","Having children and buying a home","Establishing careers and financial independence separately","Merging families and having the wedding ceremony"], correctIndex: 0, rationale: "The coupling stage requires forming a new marital/partnership system with its own identity while renegotiating relationships with each partner's family of origin and friend networks. Failure to establish clear couple boundaries is a common source of early conflict.", difficulty: 2, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-909", stem: "In narrative family therapy, 'landscape of action' questions explore:", options: ["The sequence of events and actions that constitute the story across time","The emotional meaning of events","The family's physical environment","Behavioral homework compliance"], correctIndex: 0, rationale: "White distinguished between landscape of action questions (what happened, in what sequence, over what time) and landscape of identity/meaning questions (what this says about values, beliefs, purposes). Both are needed to develop rich alternative narratives.", difficulty: 4, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-910", stem: "A Bowen-trained therapist working with a highly anxious couple would most likely:", options: ["Help each partner examine their family of origin patterns and increase self-differentiation","Teach communication skills and conflict resolution techniques","Prescribe medication for anxiety","Focus exclusively on the presenting marital complaint"], correctIndex: 0, rationale: "Bowen therapy addresses anxiety by increasing each partner's differentiation. The therapist helps them identify how their family of origin patterns contribute to current reactivity, encouraging self-focus and de-triangulation rather than other-focus.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-911", stem: "In structural family therapy, 'complementarity' refers to:", options: ["The reciprocal nature of family roles where each member's behavior is influenced by and influences others","Each family member acting independently","Family members having identical roles","The therapist complementing the family"], correctIndex: 0, rationale: "Complementarity in structural therapy highlights that family members' behaviors are reciprocally determined. One member's overfunction enables another's underfunction, and vice versa. Changing one member's position necessarily shifts the complementary role.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-912", stem: "A strategic family therapist using an 'ordeal' technique (Haley) would:", options: ["Assign a task more unpleasant than the symptom that must be performed whenever the symptom occurs","Prescribe medication to make symptoms worse","Deliberately create family crises","Punish the symptomatic family member"], correctIndex: 0, rationale: "Haley's ordeal technique involves prescribing a task that is more unpleasant than the symptom (but beneficial, like exercise) to be performed whenever symptoms occur. The symptom becomes too 'costly,' motivating the person to give it up.", difficulty: 4, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-913", stem: "In narrative therapy, 'scaffolding conversations' involve:", options: ["Structuring questions to gradually move from the known and familiar to the possible and new","Building a physical scaffold for the family to climb","Providing step-by-step behavioral instructions","Creating rigid conversational structures"], correctIndex: 0, rationale: "White borrowed Vygotsky's scaffolding concept, designing sequences of questions that incrementally bridge the gap between the known (current understanding) and the possible (new perspectives), facilitating movement toward preferred stories.", difficulty: 4, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-914", stem: "The genogram symbol for a miscarriage is:", options: ["A small triangle (or X through a small triangle)","A filled circle","An empty square","A star symbol"], correctIndex: 0, rationale: "In standard genogram notation, a small triangle represents a pregnancy loss (miscarriage or abortion). A stillbirth is typically represented by a filled symbol (square or circle based on sex) with an X. These symbols track reproductive history and losses.", difficulty: 2, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-915", stem: "Bowen's concept of 'de-triangulation' in therapy involves:", options: ["Helping an individual disengage from triangulated positions in the family while maintaining emotional contact with each party","Cutting off contact with all family members involved in triangles","Adding more family members to therapy to dilute the triangle","The therapist inserting themselves into the family triangle"], correctIndex: 0, rationale: "De-triangulation involves coaching the individual to stay connected to both members of a conflictual dyad without taking sides, absorbing anxiety, or being drawn into the middle. This requires increased differentiation and tolerance of anxiety.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-916", stem: "In the family life cycle, families dealing with later-life issues must navigate:", options: ["Dealing with physiological decline, loss of peers and partners, preparation for death, and maintaining functioning despite loss","Only financial planning for retirement","Exclusively childcare for grandchildren","Career advancement opportunities"], correctIndex: 0, rationale: "The later-life family stage involves managing declining health, supporting the older generation while maintaining one's own functioning, dealing with loss of spouse and peers, conducting life review, and establishing roles in wisdom-sharing with younger generations.", difficulty: 2, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-917", stem: "A structural family therapist identifies a family where the children have no privacy, the parents monitor every conversation, and no one has independent friendships. This family pattern demonstrates:", options: ["Enmeshed boundaries with diffuse subsystem boundaries","Disengaged boundaries with rigid subsystem boundaries","Clear and healthy boundaries","An appropriately protective family environment"], correctIndex: 0, rationale: "The absence of privacy, excessive monitoring, and lack of independent relationships indicate enmeshment with diffuse boundaries. Members are over-involved with each other, sacrificing individual autonomy and development.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-918", stem: "The Milan systemic intervention of 'invariant prescription' (Selvini Palazzoli) involved:", options: ["A standardized homework assignment given to parents directing them to disappear together without explanation to disrupt the family game","A medication prescription for the entire family","A standard opening statement used in every session","An invariable seating arrangement"], correctIndex: 0, rationale: "The invariant prescription was a controversial technique where parents were told to go out together without telling the children where or when they'd return. It was designed to disrupt the pathological family 'game' by strengthening the parental coalition and creating mystery.", difficulty: 5, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-919", stem: "In narrative family therapy, 'absent but implicit' refers to:", options: ["Values, hopes, and commitments that are implied by the person's response to problems even when not explicitly stated","Family members who cannot attend therapy","Unconscious defense mechanisms","Hidden family secrets"], correctIndex: 0, rationale: "White's concept of 'absent but implicit' recognizes that expressions of distress implicitly reference what the person values. If someone grieves a lost relationship, connection is implicitly valued. The therapist draws out these unspoken values to enrich the alternative story.", difficulty: 5, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-920", stem: "A Bowen therapist would view a client's chronic physical symptoms as potentially reflecting:", options: ["The absorption of family system anxiety through the body when differentiation is low","A purely biomedical condition with no systemic components","The client's deliberate attempt to gain family attention","An unrelated medical condition"], correctIndex: 0, rationale: "Bowen theory suggests that in the nuclear family emotional system, one pattern of managing anxiety is dysfunction in a spouse, which can manifest as chronic physical illness. Low differentiation makes the individual more vulnerable to absorbing and somatizing system anxiety.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-921", stem: "In structural family therapy, 'intensity' as a technique involves:", options: ["Repeating or amplifying a therapeutic message until it breaks through the family's typical transactional patterns","Speaking loudly to get the family's attention","Using confrontational language exclusively","Increasing the frequency of sessions"], correctIndex: 0, rationale: "Intensity (Minuchin) involves the therapist increasing the affective or temporal force of a message through repetition, extending the duration of an interaction, or increasing emotional intensity to overcome the family's threshold for registering change.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-922", stem: "The concept of 'equifinality' in family systems theory states that:", options: ["Different initial conditions can lead to the same outcome, and the same initial conditions can lead to different outcomes","All families are destined for the same outcome","Therapy always produces the same results regardless of approach","Families follow predetermined developmental paths"], correctIndex: 0, rationale: "Equifinality is a general systems theory principle applied to families, meaning that the current state of the system is independent of initial conditions - similar presenting problems can arise from very different family histories and dynamics.", difficulty: 4, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-923", stem: "A family genogram reveals that in each generation, the youngest daughter becomes the primary caretaker for aging parents. This pattern represents:", options: ["A multigenerational legacy or rule about gender roles and family obligations","A coincidence without therapeutic significance","Healthy family functioning","Legal requirements for eldercare"], correctIndex: 0, rationale: "Recurring genogram patterns reveal multigenerational legacies - unspoken family rules, role assignments, and expectations transmitted across generations. Exploring this pattern helps the current youngest daughter understand the pressure she may feel and choose consciously.", difficulty: 2, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-924", stem: "Strategic family therapy's concept of 'first-session task' (de Shazer) involves:", options: ["Asking the family to observe what happens in their lives that they want to continue","Immediately confronting the family's dysfunctional patterns","Completing extensive intake paperwork","Having each family member describe their childhood"], correctIndex: 0, rationale: "The first-session task (solution-focused/strategic) directs the family's attention to existing strengths and desired behaviors. By observing what's already working, the family shifts from a problem focus to a solution focus from the first session.", difficulty: 2, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-925", stem: "In the family life cycle, 'horizontal stressors' differ from 'vertical stressors' in that:", options: ["Horizontal stressors are developmental and unpredictable events occurring over time, while vertical stressors are multigenerational patterns and legacies","Horizontal stressors only affect one generation","Vertical stressors are always more severe","Horizontal stressors are always preventable"], correctIndex: 0, rationale: "Carter and McGoldrick distinguished vertical stressors (patterns, myths, secrets, legacies transmitted down generations) from horizontal stressors (normative developmental transitions and unpredictable events occurring in current time). Their intersection creates the family's level of stress.", difficulty: 4, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-926", stem: "A structural family therapist who physically moves to sit between an enmeshed mother and daughter during a session is using:", options: ["Spatial manipulation to create a physical boundary between the enmeshed dyad","Arbitrary seating rearrangement","A technique borrowed from psychoanalysis","An inappropriate boundary violation"], correctIndex: 0, rationale: "In structural therapy, the therapist uses physical space as a metaphor and intervention tool. Sitting between enmeshed members creates a concrete boundary, disrupting the habitual pattern and making the enmeshment visible and available for restructuring.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-927", stem: "Narrative family therapy views problems through a postmodern lens, meaning:", options: ["Problems are socially constructed through language and dominant cultural narratives rather than reflecting objective pathology","Problems have single, discoverable causes","Only biological explanations are valid","Therapists are the sole experts on the family's problems"], correctIndex: 0, rationale: "Narrative therapy's postmodern stance views problems as constructed through dominant discourses (cultural, political, professional). Problems are not objective entities residing within people but are constituted through the stories and practices of the broader culture.", difficulty: 3, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-928", stem: "Bowen's 'I-position' involves a family member:", options: ["Making clear statements about personal beliefs and values while remaining non-reactive to others' responses","Dominating family conversations","Withdrawing from emotional engagement","Agreeing with the majority to maintain harmony"], correctIndex: 0, rationale: "The I-position reflects differentiation - the ability to define one's self clearly (stating beliefs, values, and positions) without attacking others or becoming reactive to their responses. It involves self-regulation while maintaining connection.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-929", stem: "In a genogram, a filled-in symbol (completely shaded) typically denotes:", options: ["The identified patient or the person with the presenting problem","A deceased family member","A family member who lives far away","The therapist"], correctIndex: 0, rationale: "While conventions can vary, a filled or shaded symbol on a genogram often denotes the identified patient or index person (the person around whom the genogram is centered). Death is typically shown with an X through the symbol.", difficulty: 2, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-930", stem: "The family life cycle perspective is clinically useful because it:", options: ["Helps therapists normalize family stress as often linked to predictable developmental transitions","Provides a rigid template that all families must follow","Eliminates the need for individual assessment","Only applies to traditional nuclear families"], correctIndex: 0, rationale: "The family life cycle framework helps therapists normalize distress by connecting it to predictable developmental transitions. It also highlights when families are 'off-time' or stuck at a particular transition, guiding intervention toward the developmental task.", difficulty: 1, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-931", stem: "A Milan systemic therapist ends a session with a 'closing intervention' that typically includes:", options: ["A systemic reframe or ritual prescription based on the team's formulation of the family pattern","A summary of individual diagnoses for each family member","Homework from a CBT workbook","An interpretation of each member's unconscious conflicts"], correctIndex: 0, rationale: "The Milan closing intervention is carefully crafted by the team during the intersession break. It typically includes a positive connotation of the family's behavior and may include a ritual or behavioral prescription designed to perturb the system.", difficulty: 3, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-932", stem: "In structural family therapy, 'accommodation' during the joining phase means:", options: ["The therapist adjusting their behavior to fit the family's rules, tempo, and communication style","The family adjusting to the therapist's preferred style","Moving the therapy location to the family's home","Providing financial accommodations for session fees"], correctIndex: 0, rationale: "Accommodation is a joining technique where the therapist temporarily adjusts to the family's transactional style - using their language, respecting their pace, and following their affective tone. This builds alliance and acceptance before restructuring begins.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-933", stem: "In narrative therapy with families, 'outsider witness practices' involve:", options: ["Selected people listening to the family's story and offering structured reflections about what resonated with them","Outside observers conducting research on the therapy process","Family members who were not present hearing about the session","Witnesses from the legal system attending therapy"], correctIndex: 0, rationale: "Outsider witness practices (White) involve carefully selected witnesses who listen to the family's story and offer reflections following a specific protocol: what caught their attention, what images it evoked, how it resonated with their own experience, and where they've been transported.", difficulty: 4, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-934", stem: "Bowen theory suggests that the family member most likely to be 'triangled in' during parental conflict is:", options: ["The child who is most emotionally attached to the parents or most vulnerable to the family projection process","The oldest child always","The youngest child always","A randomly selected family member"], correctIndex: 0, rationale: "The child most involved in the family projection process - often the one most emotionally reactive or most focused upon by the parents - is most susceptible to triangulation. This child may develop symptoms that serve to stabilize the parental relationship.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-935", stem: "A family in which the father is extremely rigid, rarely shows emotion, and keeps strict control while the mother is warm but ineffectual demonstrates what structural pattern?", options: ["Complementary overfunction-underfunction pattern with rigid boundaries around the father and diffuse boundaries around the mother","A healthy functional structure","A symmetrical pattern","A normal cultural variation"], correctIndex: 0, rationale: "This family demonstrates a complementary pattern where one parent's rigidity and over-control (overfunctioning) enables the other's ineffectual warmth (underfunctioning). The boundaries differ across subsystems - rigid around the father, diffuse around the mother.", difficulty: 4, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-936", stem: "The strategic therapy concept of 'reframing' involves:", options: ["Changing the conceptual or emotional framework through which a situation is viewed without changing the situation itself","Physically rearranging furniture in the therapy room","Changing the family's living situation","Replacing one family member's role with another's"], correctIndex: 0, rationale: "Reframing offers a new meaning for the same facts, changing the family's perception and consequently their response. For example, reframing a child's 'defiance' as 'trying to get father's attention' shifts the family from blame to systemic understanding.", difficulty: 2, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-937", stem: "In the genogram, a dotted line between two individuals typically represents:", options: ["A distant or tenuous relationship","An extremely close relationship","A conflictual relationship","A legal relationship"], correctIndex: 0, rationale: "Dotted or dashed lines in genogram relationship notation typically indicate emotional distance or a tenuous connection. Various line types visually represent relationship qualities: double lines for closeness, zigzag for conflict, and dotted for distance.", difficulty: 1, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-938", stem: "In narrative family therapy, the therapist adopts a position of 'decentered but influential,' meaning:", options: ["The therapist does not impose their agenda but actively structures conversations that facilitate new meaning-making","The therapist is passive and non-directive","The therapist is the central expert directing the family","The therapist alternates between directive and non-directive styles randomly"], correctIndex: 0, rationale: "The decentered-but-influential stance means the family's knowledge and experience remain central (not the therapist's expertise), while the therapist actively uses questions, reflections, and curiosity to create conditions for new possibilities and preferred stories.", difficulty: 4, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-939", stem: "Bowen's 'emotional reactivity' refers to:", options: ["The degree to which a person automatically responds to emotional stimuli from others with their own emotional response","A person's capacity for deep emotional processing","The therapist's emotional reaction to the family","A family's collective emotional intelligence"], correctIndex: 0, rationale: "Emotional reactivity is the automatic, instinctive emotional response triggered by the emotional field of others. Higher differentiation is associated with lower reactivity and greater capacity for thoughtful response rather than automatic reaction.", difficulty: 2, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-940", stem: "A structural family therapist working with a single-parent family where the eldest child has assumed a parental role would:", options: ["Work to restore the parent to the executive position while acknowledging the child's contributions and relieving them of inappropriate responsibility","Reinforce the child's parental role as helpful to the family","Remove the child from the family system","Focus exclusively on the single parent's dating life"], correctIndex: 0, rationale: "The parentified child has crossed generational boundaries. The therapist restructures by empowering the parent to resume executive authority while sensitively relieving the child of inappropriate burdens, validating their contributions, and restoring their role as a child.", difficulty: 3, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-941", stem: "The Milan systemic approach originally used sessions spaced approximately:", options: ["One month apart, allowing time for the family to process and respond to the intervention","Daily for the first week","Weekly without variation","Every six months"], correctIndex: 0, rationale: "The Milan team originally spaced sessions about a month apart, believing that systemic change takes time to ripple through the family system. This spacing allowed the family to respond to the intervention and bring observable changes to the next session.", difficulty: 3, category: "Family Systems Therapy", topic: "Milan Systemic Therapy" },
  { id: "rp-942", stem: "In family therapy, the concept of 'isomorphism' refers to:", options: ["Parallel patterns that appear at different levels of the system, such as similar dynamics in the family and the treatment team","All family members having identical symptoms","The family being a mirror image of the therapist's family","Identical treatment protocols for all families"], correctIndex: 0, rationale: "Isomorphism describes structural parallels between systems at different levels. For example, a power struggle between parents may be mirrored in a power struggle between co-therapists, or between the therapy team and the referring agency.", difficulty: 5, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-943", stem: "In narrative family therapy, 'documents of identity' such as therapeutic letters and certificates serve to:", options: ["Create tangible records that validate and sustain the preferred story beyond the therapy sessions","Replace verbal therapy entirely","Serve as legal documentation of treatment","Satisfy insurance requirements for treatment documentation"], correctIndex: 0, rationale: "White and Epston used therapeutic documents (letters, certificates of achievement, declarations) to extend the influence of therapy beyond sessions. These tangible artifacts sustain the preferred story and can be revisited long after therapy ends.", difficulty: 3, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-944", stem: "A genogram that shows three generations of men dying before age 55 from heart disease would be clinically relevant for:", options: ["Identifying intergenerational health patterns and their potential psychological impact on current family members","Only medical records purposes","Insurance documentation","Legal inheritance planning"], correctIndex: 0, rationale: "Beyond medical risk, this genogram pattern may create anticipatory anxiety, fatalistic beliefs, or urgency in current-generation males. Understanding the family's meaning-making around this pattern is crucial for addressing associated psychological impacts.", difficulty: 2, category: "Family Systems Therapy", topic: "Genograms" },
  { id: "rp-945", stem: "Carter and McGoldrick emphasized that the family life cycle framework must be adapted for:", options: ["Diverse family forms including single-parent families, remarried families, LGBTQ+ families, and families of different cultural backgrounds","Only traditional nuclear families","Families in therapy exclusively","Upper-middle-class families only"], correctIndex: 0, rationale: "Carter and McGoldrick recognized that the original family life cycle framework was based on traditional nuclear families and needed adaptation for diverse family structures, cultural contexts, socioeconomic realities, and changing social norms.", difficulty: 1, category: "Family Systems Therapy", topic: "Family Life Cycle" },
  { id: "rp-946", stem: "A strategic therapist working with a family where the parents have tried 'everything' to get their teenager to behave might use:", options: ["A 'restraining' technique suggesting the family should not change too quickly or that change might be dangerous","More of the same failed solutions at higher intensity","Punishment strategies the parents have not yet tried","Individual therapy for the teenager only"], correctIndex: 0, rationale: "Restraining techniques (go slow, danger of change) create a therapeutic bind: if the family resists the restraint and changes, the problem improves; if they comply, the therapist maintains influence. This interrupts the 'more of the same' cycle of failed solutions.", difficulty: 4, category: "Family Systems Therapy", topic: "Strategic Family Therapy" },
  { id: "rp-947", stem: "In Bowen theory, working on one's 'family of origin' involves:", options: ["An adult returning to their family of origin to observe patterns, detriangulate, and increase differentiation in their original family system","Moving back into the parents' home","Blaming parents for current problems","Cutting off contact with the family of origin entirely"], correctIndex: 0, rationale: "Bowen believed the most effective therapy involved coaching individuals to return to their family of origin, observe emotional patterns, develop person-to-person relationships with each family member, and practice differentiation in the system where their patterns were formed.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
  { id: "rp-948", stem: "In structural family therapy, Minuchin's concept of 'family structure' refers to:", options: ["The invisible set of functional demands that organize how family members interact - the predictable patterns of transaction","The physical arrangement of the family's living space","The legal documents defining family relationships","The family's socioeconomic status"], correctIndex: 0, rationale: "Family structure is the invisible set of rules governing transactions between members. These patterns become predictable and self-reinforcing. Structure includes subsystems, boundaries, hierarchies, and the family's characteristic transactional patterns.", difficulty: 2, category: "Family Systems Therapy", topic: "Structural Family Therapy" },
  { id: "rp-949", stem: "In narrative therapy, the question 'What does it say about you as a person that you were able to stand up to the depression yesterday?' is an example of:", options: ["A landscape of identity question that links actions to character, values, and beliefs","A diagnostic question","A circular question","A solution-focused scaling question"], correctIndex: 0, rationale: "Landscape of identity questions (White) invite the person to reflect on what their actions reveal about their character, values, commitments, and beliefs. This enriches the alternative story by connecting events to identity claims.", difficulty: 3, category: "Family Systems Therapy", topic: "Narrative Family Therapy" },
  { id: "rp-950", stem: "In Bowen theory, the level of differentiation of the family is primarily transmitted through:", options: ["The emotional process between parents and children, particularly the family projection process","Formal education and instruction","Genetic inheritance exclusively","Community and peer influences only"], correctIndex: 0, rationale: "Differentiation levels are transmitted primarily through the emotional process between parents and children, especially through the family projection process. The child most caught in the parents' emotional system develops similar or lower differentiation than the parents.", difficulty: 3, category: "Family Systems Therapy", topic: "Bowen Theory" },
];
